dart_code.pattern:
HttpClient _makeClient(String url) {
  final client = HttpClient();
  final host = Uri.parse(url).host;
  // КРИТИЧНО: bypass системного прокси для localhost
  if (host == 'localhost' || host == '127.0.0.1' || host == '::1' ||
      host == 'host.docker.internal') {
    client.findProxy = (_) => 'DIRECT';
  }
  return client;
}

provider_resolution.logic:
// _resolveBaseUrl(provider):
// 1. Ищет env var: ${PROVIDER.toUpperCase()}_BASE_URL
//    Пример: OMNI_PROVIDER=omni → ищет OMNI_BASE_URL
// 2. Если нет — ищет в providerBaseUrls map
// 3. Если нет — бросает ArgumentError

// providerBaseUrls содержит:
// 'gemini' → 'https://generativelanguage.googleapis.com/v1beta/openai'  ← GOOGLE НАПРЯМУЮ
// 'omni'   → НЕТ в map → нужен OMNI_BASE_URL env var
// 'ollama' → 'http://localhost:11434/v1'

problem.check_db:
cd /app && node -e "
const Database = require('./node_modules/better-sqlite3');
const db = new Database('./data/storage.sqlite');
const rows = db.prepare(\"SELECT name, is_active, error_code, last_error, rate_limited_until FROM provider_connections WHERE provider='gemini'\").all();
rows.forEach(r => console.log(r.name, 'active:', r.is_active, 'error:', r.error_code, 'until:', r.rate_limited_until));
"
